<template>
  <view>
    <!-- 触发按钮 -->
    <view @click="handleUpload">
      <slot>
        <image 
          src="/static/video-icon.png" 
          style="width: 50rpx; height: 50rpx;"
        />
      </slot>
    </view>
  </view>
</template>

<script>
export default {
  methods: {
    async handleUpload() {
		console.log('handleUpload')
      try {
        // 分平台处理
        let tempFile = await this.platformChooseVideo()
        
        // 验证文件
        this.validateFile(tempFile)

        // 上传逻辑
        const videoUrl = await this.uploadFile(tempFile)
        
        this.$emit('success', videoUrl)
      } catch (error) {
        this.$emit('error', error)
      }
    },

    // 平台差异化选择
    platformChooseVideo() {
      return new Promise((resolve, reject) => {
        // 微信小程序
        // #ifdef MP-WEIXIN
        wx.chooseMedia({
          count: 1,
          mediaType: ['video'],
          sourceType: ['album', 'camera'],
          maxDuration: 60,
          success: res => resolve(res.tempFiles[0]),
          fail: reject
        })
        // #endif

        // H5
        // #ifdef H5
        const input = document.createElement('input')
        input.type = 'file'
        input.accept = 'video/*'
        input.onchange = e => {
          const file = e.target.files[0]
          resolve({
            tempFilePath: URL.createObjectURL(file),
            size: file.size,
            type: file.type
          })
        }
        input.click()
        // #endif

        // App及其他平台
        // #ifndef MP-WEIXIN || H5
        uni.chooseVideo({
          sourceType: ['album', 'camera'],
          success: res => resolve({
            tempFilePath: res.tempFilePath,
            size: res.size,
            duration: res.duration
          }),
          fail: reject
        })
        // #endif
      })
    },

    validateFile(file) {
      // 统一验证逻辑
      const maxSize = 50 * 1024 * 1024 // 50MB
      if (file.size > maxSize) {
        throw new Error('视频大小不能超过50MB')
      }
    },

    uploadFile(file) {
      return new Promise((resolve, reject) => {
		  console.log(file)
        // 微信小程序用uploadFile
        // #ifdef MP-WEIXIN
   // 修改上传逻辑
   const uploadTask = wx.uploadFile({
     url: 'https://www.ok9288.com/api/user/material_video',
     file: file.tempFilePath,
     type: 'video',
     success: (res) => {
       console.log('原始响应:', res.data) // 添加日志
	   // 状态码检查
	           if (res.statusCode < 200 || res.statusCode >= 300) {
	             reject(new Error(`HTTP Error ${res.statusCode}`))
	             return
	           }
       // 安全解析
            try {
					  console.log('进入了success')
              const data = JSON.parse(res.data)
			  	  console.log('res.data',res.data)
              if (data.code !== 0) {
				  console.log('上传失败')
                reject(new Error(data.message || '上传失败'))
                return
              }
              resolve(data.data.url)
            } catch (e) {
				 console.log('无效响应')
              console.error('无效响应:', res.data)
              reject(new Error('服务器返回格式错误'))
            }
          },
          fail: (err) => {
			  console.log('网络错误')
            reject(new Error(`网络错误: ${err.errMsg}`))
          }
   })
        
        uploadTask.onProgressUpdate(res => {
          this.$emit('progress', res.progress)
        })
        // #endif

        // H5用axios或uni.request
        // #ifdef H5
        const formData = new FormData()
        const blob = new Blob([file], { type: file.type })
        formData.append('video', blob, 'video.mp4')

        axios.post('https://www.ok9288.com/api/user/material_video', formData, {
          onUploadProgress: progressEvent => {
            const percent = Math.round(
              (progressEvent.loaded * 100) / progressEvent.total
            )
            this.$emit('progress', percent)
          }
        }).then(res => resolve(res.data.url))
        // #endif

        // 其他平台用uni.uploadFile
        // #ifndef MP-WEIXIN || H5
      // 修改上传逻辑
      const uploadTask = wx.uploadFile({
      url: 'https://www.ok9288.com/api/user/material_video',
      file: file.tempFilePath,
      type: 'video',
        success: (res) => {
          console.log('原始响应:', res.data) // 添加日志
          try {
            const data = JSON.parse(res.data)
            resolve(data.url)
          } catch (e) {
            console.error('JSON解析失败:', e)
            reject(new Error('服务器返回格式错误'))
          }
        },
        fail: reject
      })
        
        uploadTask.onProgressUpdate = res => {
          this.$emit('progress', res.progress)
        }
        // #endif
      })
    }
  }
}
</script>